import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { Course } from '../../../core/models';

@Component({
  selector: 'app-instructor-courses-list',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './courses-list.component.html',
  styleUrl: './courses-list.component.css',
})
export class CoursesListComponent {
  loading = signal(false);
  error = signal<string | null>(null);

  courses = signal<Course[]>([
    {
      id: 'c1',
      title: 'Intro to Web Development',
      description: 'HTML, CSS, and JavaScript fundamentals.',
      moduleCount: 4,
      lessonCount: 12,
    },
    {
      id: 'c4',
      title: 'Introduction to Machine Learning',
      description: 'A gentle, hands-on tour of modern ML.',
      moduleCount: 5,
      lessonCount: 15,
    },
  ]);

  showForm = signal(false);
  newTitle = '';
  newDescription = '';

  toggleForm(): void {
    this.showForm.update((v) => !v);
  }

  create(): void {
    if (!this.newTitle.trim()) return;
    const course: Course = {
      id: 'new-' + this.newTitle.toLowerCase().replace(/\s+/g, '-'),
      title: this.newTitle.trim(),
      description: this.newDescription.trim(),
      moduleCount: 0,
      lessonCount: 0,
    };
    this.courses.update((list) => [...list, course]);
    this.newTitle = '';
    this.newDescription = '';
    this.showForm.set(false);
  }

  remove(course: Course): void {
    this.courses.update((list) => list.filter((c) => c.id !== course.id));
  }
}
